import React, { useState } from 'react'
import Page from '../components/page/page'

const Macronutrients = () => {
  const [leanBodyMass, setLeanBodyMass] = useState(80)
  const [proteinsPerKg, setProteinsPerKg] = useState(0.8)

  return (
    <Page title='Macronutrients'>
      <div>
        <label for='lean-body-mass'>Lean Body Mass (kg)</label>
        <input
          id='lean-body-mass'
          type='number'
          value={leanBodyMass}
          onChange={({ target: { value } }) => setLeanBodyMass(value)}
        />
      </div>
      <div>
        <label for='proteinsPerKg'>
          {proteinsPerKg} grams of proteins per kg
        </label>
        <input
          id='proteinsPerKg'
          max={2.6}
          min={0.8}
          onChange={({ target: { value } }) => setProteinsPerKg(value)}
          step={0.01}
          type='range'
          value={proteinsPerKg}
        />
      </div>
      <div>{Math.round(leanBodyMass * proteinsPerKg)}</div>
    </Page>
  )
}

export default Macronutrients
